 using Microsoft.VisualStudio.TestTools.UnitTesting;
 using Store;

 namespace Store.Tests;

 [TestClass]
 public sealed class ShoppingCartTests
 {
     private ShoppingCart _cart = null!;

     [TestInitialize]
     public void Setup()
     {
         _cart = new ShoppingCart();
     }

     // ── AddItem ──────────────────────────────────────────────

     [TestMethod]
     public void AddItem_SingleItem_IncreasesTotal()
     {
         _cart.AddItem("SKU-001", 2, 10.00m);

         Assert.AreEqual(20.00m, _cart.CalculateTotal());
     }

     [TestMethod]
     public void AddItem_MultipleDistinctItems_TotalReflectsAll()
     {
         _cart.AddItem("SKU-001", 1, 5.00m);
         _cart.AddItem("SKU-002", 3, 10.00m);

         Assert.AreEqual(35.00m, _cart.CalculateTotal());
     }

     [TestMethod]
     public void AddItem_SameSkuTwice_QuantityAccumulates()
     {
         _cart.AddItem("SKU-001", 2, 10.00m);
         _cart.AddItem("SKU-001", 3, 10.00m);

         // 5 * 10 = 50
         Assert.AreEqual(50.00m, _cart.CalculateTotal());
     }

     [TestMethod]
     public void AddItem_SameSkuTwice_PriceUpdatesToLatest()
     {
         _cart.AddItem("SKU-001", 1, 10.00m);
         _cart.AddItem("SKU-001", 1, 15.00m);

         // 2 * 15 = 30 (price updated to latest)
         Assert.AreEqual(30.00m, _cart.CalculateTotal());
     }

     [TestMethod]
     public void AddItem_ZeroPriceItem_TotalIsZero()
     {
         _cart.AddItem("FREE-ITEM", 5, 0.00m);

         Assert.AreEqual(0.00m, _cart.CalculateTotal());
     }

     [TestMethod]
     [DataRow(null, DisplayName = "Null SKU")]
     [DataRow("", DisplayName = "Empty SKU")]
     public void AddItem_NullOrEmptySku_ThrowsArgumentNullException(string? sku)
     {
         Assert.ThrowsExactly<ArgumentNullException>(
             () => _cart.AddItem(sku!, 1, 10.00m));
     }

     [TestMethod]
     [DataRow(0, DisplayName = "Zero quantity")]
     [DataRow(-1, DisplayName = "Negative quantity")]
     public void AddItem_InvalidQuantity_ThrowsArgumentException(int quantity)
     {
         Assert.ThrowsExactly<ArgumentException>(
             () => _cart.AddItem("SKU-001", quantity, 10.00m));
     }

     [TestMethod]
     public void AddItem_NegativePrice_ThrowsArgumentException()
     {
         Assert.ThrowsExactly<ArgumentException>(
             () => _cart.AddItem("SKU-001", 1, -5.00m));
     }

     // ── RemoveItem ───────────────────────────────────────────

     [TestMethod]
     public void RemoveItem_ExistingItem_RemovesFromCart()
     {
         _cart.AddItem("SKU-001", 2, 10.00m);
         _cart.AddItem("SKU-002", 1, 5.00m);

         _cart.RemoveItem("SKU-001");

         Assert.AreEqual(5.00m, _cart.CalculateTotal());
     }

     [TestMethod]
     public void RemoveItem_OnlyItem_CartBecomesEmpty()
     {
         _cart.AddItem("SKU-001", 2, 10.00m);

         _cart.RemoveItem("SKU-001");

         Assert.AreEqual(0.00m, _cart.CalculateTotal());
     }

     [TestMethod]
     public void RemoveItem_NonExistingSku_ThrowsKeyNotFoundException()
     {
         Assert.ThrowsExactly<KeyNotFoundException>(
             () => _cart.RemoveItem("NO-SUCH-SKU"));
     }

     [TestMethod]
     [DataRow(null, DisplayName = "Null SKU")]
     [DataRow("", DisplayName = "Empty SKU")]
     public void RemoveItem_NullOrEmptySku_ThrowsArgumentNullException(string? sku)
     {
         Assert.ThrowsExactly<ArgumentNullException>(
             () => _cart.RemoveItem(sku!));
     }

     // ── CalculateTotal ───────────────────────────────────────

     [TestMethod]
     public void CalculateTotal_EmptyCart_ReturnsZero()
     {
         Assert.AreEqual(0.00m, _cart.CalculateTotal());
     }

     [TestMethod]
     public void CalculateTotal_SingleItem_ReturnsQuantityTimesPrice()
     {
         _cart.AddItem("SKU-001", 3, 7.50m);

         Assert.AreEqual(22.50m, _cart.CalculateTotal());
     }

     [TestMethod]
     public void CalculateTotal_MultipleItems_ReturnsSumOfLineItems()
     {
         _cart.AddItem("A", 2, 10.00m);
         _cart.AddItem("B", 1, 25.00m);
         _cart.AddItem("C", 4, 3.00m);

         // 20 + 25 + 12 = 57
         Assert.AreEqual(57.00m, _cart.CalculateTotal());
     }

     // ── ApplyCoupon ──────────────────────────────────────────

     [TestMethod]
     public void ApplyCoupon_Save10_Applies10PercentDiscount()
     {
         _cart.AddItem("SKU-001", 1, 100.00m);
         _cart.ApplyCoupon("SAVE10");

         Assert.AreEqual(90.00m, _cart.CalculateTotal());
     }

     [TestMethod]
     public void ApplyCoupon_Flat5_Applies5DollarDiscount()
     {
         _cart.AddItem("SKU-001", 1, 20.00m);
         _cart.ApplyCoupon("FLAT5");

         Assert.AreEqual(15.00m, _cart.CalculateTotal());
     }

     [TestMethod]
     public void ApplyCoupon_InvalidCode_ThrowsArgumentException()
     {
         Assert.ThrowsExactly<ArgumentException>(
             () => _cart.ApplyCoupon("BOGUS"));
     }

     [TestMethod]
     [DataRow(null, DisplayName = "Null code")]
     [DataRow("", DisplayName = "Empty code")]
     public void ApplyCoupon_NullOrEmptyCode_ThrowsArgumentNullException(string? code)
     {
         Assert.ThrowsExactly<ArgumentNullException>(
             () => _cart.ApplyCoupon(code!));
     }

     [TestMethod]
     public void ApplyCoupon_SecondCouponReplacesFirst()
     {
         _cart.AddItem("SKU-001", 1, 100.00m);
         _cart.ApplyCoupon("SAVE10"); // 10% off = 90
         _cart.ApplyCoupon("FLAT5");  // $5 off = 95

         Assert.AreEqual(95.00m, _cart.CalculateTotal());
     }

     // ── Edge Cases / State Transitions ───────────────────────

     [TestMethod]
     public void CalculateTotal_Flat5DiscountExceedsSubtotal_ReturnsZero()
     {
         _cart.AddItem("CHEAP", 1, 3.00m);
         _cart.ApplyCoupon("FLAT5");

         Assert.AreEqual(0.00m, _cart.CalculateTotal());
     }

     [TestMethod]
     public void CalculateTotal_Save10OnEmptyCart_ReturnsZero()
     {
         _cart.ApplyCoupon("SAVE10");

         Assert.AreEqual(0.00m, _cart.CalculateTotal());
     }

     [TestMethod]
     public void AddThenRemove_TotalReflectsRemainingItems()
     {
         _cart.AddItem("A", 1, 10.00m);
         _cart.AddItem("B", 1, 20.00m);
         _cart.RemoveItem("A");

         Assert.AreEqual(20.00m, _cart.CalculateTotal());
     }

     [TestMethod]
     public void ApplyCouponThenAddItems_DiscountAppliesToNewTotal()
     {
         _cart.ApplyCoupon("SAVE10");
         _cart.AddItem("SKU-001", 2, 50.00m);

         // 100 - 10% = 90
         Assert.AreEqual(90.00m, _cart.CalculateTotal());
     }

     [TestMethod]
     public void AddRemoveAdd_TotalReflectsCurrentState()
     {
         _cart.AddItem("A", 1, 10.00m);
         _cart.RemoveItem("A");
         _cart.AddItem("B", 2, 15.00m);

         Assert.AreEqual(30.00m, _cart.CalculateTotal());
     }

     [TestMethod]
     public void RemoveItem_AfterRemove_SecondRemoveThrows()
     {
         _cart.AddItem("SKU-001", 1, 10.00m);
         _cart.RemoveItem("SKU-001");

         Assert.ThrowsExactly<KeyNotFoundException>(
             () => _cart.RemoveItem("SKU-001"));
     }

     [TestMethod]
     public void CalculateTotal_LargeQuantityAndPrice_ReturnsCorrectValue()
     {
         _cart.AddItem("BULK", 1000, 99.99m);

         Assert.AreEqual(99990.00m, _cart.CalculateTotal());
     }

     [TestMethod]
     public void ApplyCoupon_Save10_MultipleItems_DiscountsEntireSubtotal()
     {
         _cart.AddItem("A", 2, 25.00m);  // 50
         _cart.AddItem("B", 1, 30.00m);  // 30
         _cart.ApplyCoupon("SAVE10");

         // (50 + 30) * 0.90 = 72
         Assert.AreEqual(72.00m, _cart.CalculateTotal());
     }
 }
